    63→function parseLocation(input: unknown): SubmissionLocation | null {
    64→  if (!input || typeof input !== "object") return null;
    65→  const location = input as { latitude?: unknown; longitude?: unknown };
    66→  const latitude = typeof location.latitude === "string" ? Number(location.latitude) : (location.latitude as number);
    67→  const longitude = typeof location.longitude === "string" ? Number(location.longitude) : (location.longitude as number);
    68→  if (!Number.isFinite(latitude) || !Number.isFinite(longitude)) return null;
    69→  return { latitude, longitude };
    70→}
    71→
    72→function hasValue(input: unknown): boolean {
    73→  if (typeof input === "string") return Boolean(input.trim());
    74→  if (typeof input === "boolean") return true;
    75→  if (typeof input === "number") return Number.isFinite(input);
    76→  if (Array.isArray(input)) return input.length > 0;
    77→  if (input && typeof input === "object") return Object.keys(input as object).length > 0;
    78→  return false;
    79→}
    80→
    81→function trimString(input: unknown, maxLen = 256): string | null {
    82→  if (typeof input !== "string") return null;
    83→  const value = input.trim();
    84→  if (!value) return null;
    85→  return value.slice(0, maxLen);
    86→}
    87→
    88→function sanitizeClientDevice(input: unknown): ClientDeviceInfo | null {
    89→  if (!input || typeof input !== "object") return null;
    90→  const raw = input as Record<string, unknown>;
    91→  const deviceId = trimString(raw.deviceId, 128);
    92→  if (!deviceId) return null;
    93→  const platform = trimString(raw.platform, 64);
    94→  const userAgent = trimString(raw.userAgent, 256);
    95→  const memory = typeof raw.deviceMemoryGb === "number" && Number.isFinite(raw.deviceMemoryGb) ? raw.deviceMemoryGb : null;
    96→  const cpu = typeof raw.hardwareConcurrency === "number" && Number.isFinite(raw.hardwareConcurrency) ? raw.hardwareConcurrency : null;
    97→  const isLowEnd = raw.isLowEnd === true;
    98→
    99→  return {
   100→    deviceId,
   101→    platform: platform ?? undefined,
   102→    userAgent: userAgent ?? undefined,
   103→    deviceMemoryGb: memory,
   104→    hardwareConcurrency: cpu,
   105→    isLowEnd,
   106→  };
   107→}
   108→
   109→function normalizeCategory(input: string | undefined): SubmissionCategory | null {
   110→  if (!input) return null;
   111→  const raw = input.trim();
   112→  if (raw === "FUEL") return "fuel_station";
   113→  if (raw === "MOBILE_MONEY" || raw === "KIOSK") return "mobile_money";
   114→  if (raw === "PHARMACY") return "pharmacy";
   115→  if (raw === "fuel_station" || raw === "mobile_money" || raw === "pharmacy") return raw;
   116→  return null;
   117→}
