   149→function mimeToExtension(mime: string): string {
   150→  switch (mime) {
   151→    case "image/png":
   152→      return "png";
   153→    case "image/webp":
   154→      return "webp";
   155→    case "image/heic":
   156→      return "heic";
   157→    case "image/heif":
   158→      return "heif";
   159→    default:
