   275→async function buildFallbackFraudCheck(event: PointEvent): Promise<SubmissionFraudCheck | null> {
   276→  const primaryUrl = typeof event.photoUrl === "string" ? event.photoUrl.trim() : "";
   277→  const secondaryUrl = getSecondaryPhotoUrl(event);
   278→  if (!primaryUrl && !secondaryUrl) return null;
   279→
   280→  const primaryExtracted = primaryUrl ? await extractPhotoMetadataFromUrl(primaryUrl) : null;
   281→  const secondaryExtracted = secondaryUrl ? await extractPhotoMetadataFromUrl(secondaryUrl) : null;
   282→  const primaryPhoto = buildPhotoFraudMetadata({
   283→    extracted: primaryExtracted,
   284→    submissionLocation: event.location,
