   356→async function buildCombinedEvents(): Promise<PointEvent[]> {
   357→  const pointEvents = (await getPointEvents()).map(stripInlinePhotoData);
   358→  const legacySubmissions = await getLegacySubmissions();
   359→  const merged = mergePointEventsWithLegacy(pointEvents, legacySubmissions);
   360→  const seenExternalIds = new Set(
   361→    merged
   362→      .map((event) => (typeof event.externalId === "string" ? event.externalId.trim() : ""))
   363→      .filter((value) => value.length > 0),
   364→  );
   365→  const seenPointIds = new Set(merged.map((event) => event.pointId));
   366→  for (const seedEvent of BONAMOUSSADI_CURATED_SEED_EVENTS) {
   367→    const externalId = typeof seedEvent.externalId === "string" ? seedEvent.externalId.trim() : "";
   368→    if (externalId && seenExternalIds.has(externalId)) continue;
   369→    if (seenPointIds.has(seedEvent.pointId)) continue;
   370→    merged.push(seedEvent);
   371→    if (externalId) seenExternalIds.add(externalId);
   372→    seenPointIds.add(seedEvent.pointId);
   373→  }
   374→  return merged;
   375→}
