     3→export interface SubmissionAuthContext {
     4→  id: string;
     5→  isAdmin: boolean;
     6→}
     7→
     8→type RawAuth = {
     9→  id: string;
    10→  token?: unknown;
    11→} | null;
    12→
    13→export function normalizeActorId(input: string): string {
    14→  return input.toLowerCase().trim();
    15→}
    16→
    17→export function toSubmissionAuthContext(auth: RawAuth): SubmissionAuthContext | null {
    18→  if (!auth || typeof auth.id !== "string") return null;
    19→  const id = normalizeActorId(auth.id);
    20→  if (!id) return null;
    21→  const token = auth.token as { isAdmin?: unknown } | undefined;
    22→  const isAdmin = token?.isAdmin === true;
    23→  return { id, isAdmin };
    24→}
    25→
    26→export function redactEventUserIds(events: PointEvent[]): Array<Omit<PointEvent, "userId">> {
    27→  return events.map(({ userId: _userId, ...rest }) => rest as Omit<PointEvent, "userId">);
    28→}
    29→
    30→export function filterEventsForViewer(events: PointEvent[], viewer: SubmissionAuthContext): PointEvent[] {
    31→  if (viewer.isAdmin) return events;
    32→  return events.filter((event) => normalizeActorId(event.userId) === viewer.id);
    33→}
    34→
    35→export function canViewEventDetail(event: PointEvent, viewer: SubmissionAuthContext): boolean {
    36→  if (viewer.isAdmin) return true;
    37→  return normalizeActorId(event.userId) === viewer.id;
    38→}
    39→
    40→export function resolveAdminViewAccess(viewer: SubmissionAuthContext | null): "ok" | "unauthorized" | "forbidden" {
    41→  if (!viewer) return "unauthorized";
    42→  if (!viewer.isAdmin) return "forbidden";
    43→  return "ok";
    44→}
